using System;
using System.Reflection;
using System.Text.Json;
using System.Text.Json.Serialization;
using Azure;
var converterType = typeof(ResponseError).GetNestedType("Converter", BindingFlags.Public | BindingFlags.NonPublic);
if (converterType != null) {
    Console.WriteLine($"Converter type: {converterType.FullName}, IsPublic: {converterType.IsPublic}, IsNestedPublic: {converterType.IsNestedPublic}");
    foreach (var ctor in converterType.GetConstructors(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance))
        Console.WriteLine($"  Ctor: public={ctor.IsPublic} params={ctor.GetParameters().Length}");
    // Try to instantiate and use
    var converter = (JsonConverter)Activator.CreateInstance(converterType, true);
    Console.WriteLine($"Converter instance: {converter?.GetType()}");
    // Verify round-trip
    var opts = new JsonSerializerOptions();
    opts.Converters.Add(converter);
    var err = JsonSerializer.Deserialize<ResponseError>("{\"code\":\"TestCode\",\"message\":\"TestMsg\",\"target\":\"tgt\"}", opts);
    Console.WriteLine($"Code={err.Code} Message={err.Message}");
    var json = JsonSerializer.Serialize(err, opts);
    Console.WriteLine($"Serialized: {json}");
}
EOF
